**Stub + Queue Replay는 어떻게 동작하나?**

```typescript
// 사용자 코드 (SDK 로드 전에 실행될 수 있음)
const kit = new TapKit({ apiKey: "..." });
kit.show();  // SDK 아직 로드 안 됨 - 큐에 저장

// 내부 동작
class TapKit {
  #pendingCalls: Array<{method: string, args: unknown[]}> = [];

  show() {
    if (this.instance) {
      this.instance.show();
    } else {
      this.#pendingCalls.push({ method: "show", args: [] });
    }
  }

  // SDK 로드 완료 후
  private replayPendingCalls() {
    for (const call of this.#pendingCalls) {
      this.instance[call.method](...call.args);
    }
  }
}
```

